insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'gruppespill-1', '08', 'Gruppespill',
  'Gruppespill — omgang 1', 'Det som faktisk skjedde i åpningsrunden.', 'vm-gruppespill-1', 'medium',
  '[{"category": "Resultat", "q": "Hvordan endte åpningskampen mellom Mexico og Sør-Afrika på Estadio Azteca 11. juni?", "options": ["1–0 til Mexico", "0–0", "2–0 til Mexico", "2–1 til Mexico"], "correct": 2, "explanation": "Julián Quiñones scoret i det 9. minutt og Raúl Jiménez doblet i andre omgang — i en kamp med hele tre røde kort."}, {"category": "Målscorer", "q": "Hvem stanget inn Mexicos andre mål mot Sør-Afrika — sitt aller første VM-mål?", "options": ["Hirving Lozano", "Santiago Giménez", "Julián Quiñones", "Raúl Jiménez"], "correct": 3, "explanation": "Jiménez headet inn på pasning fra Roberto Alvarado; Quiñones hadde scoret det første."}, {"category": "Drama", "q": "Sør-Korea lå under 0–1 mot Tsjekkia, men snudde til 2–1. Hvem scoret det avgjørende målet i det 80. minutt?", "options": ["Oh Hyeon-gyu", "Cho Gue-sung", "Hwang In-beom", "Son Heung-min"], "correct": 0, "explanation": "Hwang In-beom utlignet i det 67. og la deretter målgivende til Oh Hyeon-gyus vinnermål."}, {"category": "Resultat", "q": "Hva ble resultatet i storkampen mellom Brasil og Marokko i gruppe C?", "options": ["2–1 til Brasil", "2–0 til Marokko", "1–1", "3–2 til Brasil"], "correct": 2, "explanation": "Ismael Saibari sendte Marokko i ledelsen før Vinícius Júnior utlignet for Brasil."}, {"category": "Stjerner", "q": "Hvem utlignet for Brasil til 1–1 mot Marokko?", "options": ["Raphinha", "Vinícius Júnior", "Endrick", "Rodrygo"], "correct": 1, "explanation": "Vinícius Júnior svarte på Marokkos ledermål; Alisson reddet Brasil med en sen dobbeltredning."}, {"category": "Rekord", "q": "Curaçao spilte sin aller første VM-kamp 14. juni. Hvordan endte det mot Tyskland?", "options": ["Tap 0–3", "Tap 2–4", "Uavgjort 1–1", "Tap 1–7"], "correct": 3, "explanation": "Tyskland vant 7–1 i Houston, med Kai Havertz tomålsscorer; Curaçao er den minste nasjonen som har nådd et VM."}, {"category": "Kuriosa", "q": "Qatar tok sitt aller første VM-poeng med en sen utligning til 1–1. Mot hvilket lag?", "options": ["Tsjekkia", "Sør-Korea", "Sveits", "Marokko"], "correct": 2, "explanation": "Breel Embolo hadde gitt Sveits ledelsen på straffe; Qatar tapte alle tre kampene i 2022 og hadde aldri tatt poeng før."}, {"category": "Historie", "q": "Australia vant 2–0 over et lag som var tilbake i VM for første gang siden 2002. Hvilket?", "options": ["Iran", "Saudi-Arabia", "Tyrkia", "Tunisia"], "correct": 2, "explanation": "Nestory Irankunda og Connor Metcalfe scoret i Vancouver; Tyrkia kom på tredjeplass i VM 2002 og hadde ventet 24 år."}, {"category": "Målscorer", "q": "John McGinn scoret det eneste målet da Skottland vant 1–0 i sin VM-åpning. Mot hvilket lag?", "options": ["Haiti", "Jamaica", "Panama", "Honduras"], "correct": 0, "explanation": "McGinn avgjorde i det 28. minutt på Gillette Stadium i Foxborough."}, {"category": "Arena", "q": "På hvilket legendariske stadion ble VM 2026 sparket i gang med Mexico–Sør-Afrika?", "options": ["Estadio Azteca", "Estadio BBVA", "MetLife Stadium", "SoFi Stadium"], "correct": 0, "explanation": "Azteca i Mexico by er nå vert for sitt tredje VM (1970, 1986, 2026)."}]'::jsonb, 'open', 8, true
)
on conflict (event_id, slug) do update set
  num=excluded.num, phase=excluded.phase, title=excluded.title, sub=excluded.sub,
  hero_img=excluded.hero_img, difficulty=excluded.difficulty, questions=excluded.questions,
  status=excluded.status, sort=excluded.sort, published=excluded.published;
